sql:
SELECT recipient_name
FROM recipients
ORDER BY recipient_name;

SELECT SUM(amount_disbursed) AS total_disbursed
FROM grant_status
WHERE status = 'awarded';

SELECT grant_id, AVG(score) AS average_score
FROM grant_evaluations
GROUP BY grant_id;

SELECT recipient_name, type, contact_email
FROM recipients
WHERE recipient_id = 0;

